/* ─── Helpers ───────────────────────────────────────────────────────────── */
const fmtPrice = (p) => typeof p === "number" ? `$${p.toFixed(2)}` : p;
const toNum    = (p) => typeof p === "number" ? p : parseFloat(String(p).replace("$","")) || 0;

const seedRandom = (s) => { let x = s % (2**35-31); return () => (x = (x*185852) % (2**35-31)) / (2**35-31); };
const fetchTimes = (d) => {
  const r = seedRandom(new Date(d).getDate() || new Date().getDate());
  const sl = [];
  for (let h = 17; h <= 23; h++) { if (r() < 0.5) sl.push(`${h}:00`); if (r() > 0.5) sl.push(`${h}:30`); }
  return sl.length ? sl : ["18:00","19:00","20:00"];
};
const timeReducer = (_, d) => fetchTimes(d);

