function NutriBar({ label, val, max, color }) {
  const pct = Math.min(100, Math.round((val / max) * 100));
  return (
    <div className="nutri-bar-row">
      <div className="nutri-bar-label">
        <span>{label}</span>
        <span style={{color}}>{val}g <span style={{color:"#aaa",fontWeight:400}}>({pct}% DV)</span></span>
      </div>
      <div className="nutri-bar-track">
        <div className="nutri-bar-fill" style={{width:`${pct}%`, background:color}} />
      </div>
    </div>
  );
}

